
    const months=['January','February','March','April','May','June','July','August','September','October','November','December'];
    const ruMonths=['январь','февраль','март','апрель','май','июнь','июль','август','сентябрь','октябрь','ноябрь','декабрь'];
    const ruMonthsGen=['января','февраля','марта','апреля','мая','июня','июля','августа','сентября','октября','ноября','декабря'];
    const emotions=[['calm','спокойствие','#EFE7CE'],['joy','радость','#F2D65C'],['inspiration','вдохновение','#86C4A0'],['interest','интерес','#9FDCCB'],['courage','смелость','#8FBEE8'],['surprise','удивление','#CBE07A'],['admiration','восхищение','#EDA9D2'],['pride','гордость','#79CFD8'],['laziness','лень','#CFCBAE'],['tiredness','усталость','#CFCFCF'],['sadness','грусть','#A9BECB'],['anxiety','тревога','#BDB4E8'],['irritation','раздражение','#F09A8E'],['anger','злость','#CE7A5E']];
    const today=new Date(), storeKey='lifeMosaic.v4';try{['lifeMosaic.v1','lifeMosaic.v2','lifeMosaic.v3'].forEach(k=>localStorage.removeItem(k))}catch(e){}
    const seed={selectedYear:today.getFullYear(),selectedMonth:today.getMonth(),selectedDay:today.getDate(),currentBookId:'',currentWatchId:'',balance:[{id:'bal1',name:'Здоровье',score:5,desc:'тело, сон, энергия'},{id:'bal2',name:'Карьера',score:5,desc:'работа, самореализация'},{id:'bal3',name:'Финансы',score:5,desc:'деньги, стабильность'},{id:'bal4',name:'Любовь',score:5,desc:'партнёр, отношения'},{id:'bal5',name:'Близкие',score:5,desc:'семья, друзья'},{id:'bal6',name:'Развитие',score:5,desc:'рост, обучение'},{id:'bal7',name:'Отдых',score:5,desc:'хобби, восстановление'},{id:'bal8',name:'Смысл',score:5,desc:'ценности, духовность'}],days:{},pulse:{},metrics:[],goals:[],trackers:[],trackerSuccess:[],books:[],bookArchive:[],watches:[],watchArchive:[],lists:[],dreams:[]};
    let data=load(); migrate();
    function load(){try{return merge(seed,JSON.parse(localStorage.getItem(storeKey)||'{}'))}catch(e){return structuredClone(seed)}}
    function merge(a,b){if(Array.isArray(a))return Array.isArray(b)?b:a; if(a&&typeof a==='object'){const o={...a,...(b||{})}; for(const k in a) if(b&&k in b) o[k]=merge(a[k],b[k]); return o} return b??a}
    function uid(){return crypto.randomUUID?crypto.randomUUID():String(Date.now()+Math.random())}
    function save(){localStorage.setItem(storeKey,JSON.stringify(data))}
    function key(y=data.selectedYear,m=data.selectedMonth,d=data.selectedDay){return `${y}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`}
    function dateLabel(d=data.selectedDay,m=data.selectedMonth,y=data.selectedYear,withYear=false){return `${Number(d)} ${ruMonthsGen[Number(m)]}${withYear?' '+y:''}`}
    function daysInMonth(){return new Date(data.selectedYear,data.selectedMonth+1,0).getDate()}
    function clampDay(){data.selectedDay=Math.min(data.selectedDay,daysInMonth())}
    function dayData(k=key()){return data.days[k]||(data.days[k]={emotions:[],ratings:{energy:3,anxiety:2,wellbeing:3,sociality:3,satisfaction:3},journal:{thanksDay:'',thanksSelf:'',main:'',insight:''}})}
    function pulseData(k=key()){return data.pulse[k]||(data.pulse[k]={steps:'',reading:'',readingUnit:'страницы'})}
    function unitFor(type){return ({'число':'число','минуты':'мин','литры':'л','километры':'км','да/нет':'да/нет','да-нет':'да/нет','текст':'текст'})[type]||type||''}
    function metricTypeLabel(m){return m.type==='другое'?(m.unit||'мой вариант'):m.type}
    function metricMonthTotalLabel(type,unit,values){if(type==='текст')return '';const y=data.selectedYear,mo=data.selectedMonth,dim=new Date(y,mo+1,0).getDate();let sum=0;for(let d=1;d<=dim;d++){const v=values?.[key(y,mo,d)];if(v==null||v==='')continue;if(type==='да/нет'){if(v==='да')sum++}else{const n=parseFloat(String(v).replace(',','.'));if(!isNaN(n))sum+=n}}if(type==='да/нет')return `Всего за месяц: ${sum} да`;const u=(unit&&unit!=='число'&&unit!=='текст')?' '+unit:'';return `Всего за месяц: ${Math.round(sum*100)/100}${u}`}
    function builtinMonthTotalLabel(kind,values){const y=data.selectedYear,mo=data.selectedMonth,dim=new Date(y,mo+1,0).getDate();let sum=0;for(let d=1;d<=dim;d++){let v;if(values){v=values[key(y,mo,d)]}else{const p=data.pulse[key(y,mo,d)];v=p?(kind==='steps'?p.steps:p.reading):''}const n=parseFloat(String(v==null?'':v).replace(',','.'));if(!isNaN(n))sum+=n}const u=kind==='reading'?' мин':'';return `Всего за месяц: ${Math.round(sum*100)/100}${u}`}
    function metricTypeEditor(m){return m.type==='другое'?`<input id="mType" type="hidden" value="другое"><div class="field"><label>Единица</label><input id="mUnit" value="${m.unit||''}" placeholder="например, кружки"></div>`:`<div class="field"><label>Тип</label><select id="mType">${typeOptions(m.type)}</select></div><div class="field hidden" id="customUnitWrap"><label>Единица</label><input id="mUnit" value="${m.unit||''}"></div>`}
    function formatDate(s){if(!s)return''; const [y,m,d]=s.split('-').map(Number); return d&&m&&y?`${d} ${ruMonthsGen[m-1]} ${y}`:s}
    function monthNom(m,cap=false){const v=ruMonths[Number(m)]||'';return cap?v.charAt(0).toUpperCase()+v.slice(1):v}
    function formatMonthNom(y,m,cap=false){return `${monthNom(Number(m),cap)} ${y}`}
    function formatInsightCount(n){return `${n} ${ruCount(n,['запись','записи','записей'])} внутри`}
    function previewText(t,n=70){t=String(t||'').trim();return t.length>n?t.slice(0,n).trimEnd()+'…':t}
    function dateStamp(v){return v||'0000-00-00'}
    function gradientFor(list){if(!list||!list.length)return'#FBE3EA'; const colors=list.map(id=>emotions.find(e=>e[0]===id)?.[2]).filter(Boolean); return colors.length===1?colors[0]:`linear-gradient(135deg, ${colors.join(', ')})`}
    function isRatingsDone(d){return d.emotions.length&&['energy','anxiety','wellbeing','sociality','satisfaction'].every(k=>String(d.ratings[k]??'').length)}
    function isJournalDone(d){return d.journal.thanksDay.trim()&&d.journal.thanksSelf.trim()&&d.journal.main.trim()}
    function subProgress(s){if((s.status||'')==='выполнено'||s.done)return 100; if((s.status||'')==='не начато')return 0; return Math.max(0,Math.min(100,Number(s.progress)||0))}
    function normalizeGoalWeights(g){g.sub=g.sub||[]; g.sub.forEach(s=>{if(!('status'in s))s.status=s.done?'выполнено':((Number(s.progress)||0)>0?'в процессе':'не начато'); if(s.weight==null)s.weight=''})}
    function effectiveWeights(subs){const isSet=s=>!(s.weight===''||s.weight==null||Number.isNaN(Number(s.weight)));const setSum=subs.reduce((a,s)=>a+(isSet(s)?Number(s.weight):0),0);const unset=subs.filter(s=>!isSet(s)).length;const each=unset?Math.max(0,100-setSum)/unset:0;return subs.map(s=>isSet(s)?Number(s.weight):each)}
    function goalProgress(g){normalizeGoalWeights(g); const subs=g.sub||[]; if(!subs.length)return Math.max(0,Math.min(100,Number(g.progress)||0)); const w=effectiveWeights(subs); const total=w.reduce((a,x)=>a+x,0)||100; const val=subs.reduce((a,s,i)=>a+subProgress(s)*w[i]/total,0); g.progress=Math.round(val); return g.progress}
    function goalWeightWarning(g){const subs=g.sub||[];const all=subs.length&&subs.every(s=>s.weight!==''&&s.weight!=null&&!Number.isNaN(Number(s.weight)));const sum=subs.reduce((a,s)=>a+Number(s.weight||0),0);return all&&sum>100}
    function volumeLabel(b){return `${b.mode==='minutes'?'Минут':'Страниц'}: ${Number(b.total)||0}`}
    function ensureSeries(w){if(w.type!=='сериал')return;let seasons=Array.isArray(w.seasonsData)?w.seasonsData:null;if(!seasons){const count=Number(w.seasons)||1;const total=Number(w.episodes)||0;const each=count?Math.floor(total/count):0;seasons=Array.from({length:count},(_,i)=>({episodes:i===count-1?Math.max(0,total-each*(count-1)):each,watched:i===0?Number(w.watched)||0:0,done:!!w.seasonProgress?.[i+1]}))}w.seasonsData=seasons;w.seasons=seasons.length;w.episodes=seasons.reduce((a,s)=>a+Number(s.episodes||0),0);w.watched=seasons.reduce((a,s)=>a+Number(s.watched||0),0)}
    function seriesTotals(w){ensureSeries(w);return {episodes:(w.seasonsData||[]).reduce((a,s)=>a+Number(s.episodes||0),0),watched:(w.seasonsData||[]).reduce((a,s)=>a+Number(s.watched||0),0)}}
    function ruCount(n,forms){n=Math.abs(Number(n)||0);const n10=n%10,n100=n%100;return forms[(n10===1&&n100!==11)?0:(n10>=2&&n10<=4&&(n100<12||n100>14))?1:2]}
    function bookArchiveTitle(){const n=(data.bookArchive||[]).length;return `${n} ${ruCount(n,['книга','книги','книг'])}`}
    function filmArchiveTitle(){const n=(data.watchArchive||[]).filter(w=>w.type!=='сериал').length;return `${n} ${ruCount(n,['фильм','фильма','фильмов'])} в фильмотеке`}
    function seriesArchiveTitle(){const n=(data.watchArchive||[]).filter(w=>w.type==='сериал').length;return `${n} ${ruCount(n,['сериал','сериала','сериалов'])} в фильмотеке`}
    function watchArchiveTitle(){const f=(data.watchArchive||[]).filter(w=>w.type!=='сериал').length,s=(data.watchArchive||[]).filter(w=>w.type==='сериал').length;return `${f} ${ruCount(f,['фильм','фильма','фильмов'])}, ${s} ${ruCount(s,['сериал','сериала','сериалов'])}`}
    function isTrackerComplete(t){return Number(t.target||0)>0&&(t.days||[]).length>=Number(t.target||0)}
    function curPeriod(){return `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,'0')}`}
    function periodLabel(pk){const [y,m]=(pk||curPeriod()).split('-').map(Number);return `${ruMonths[(m||1)-1]} ${y}`}
    function moveCompletedTrackers(){data.trackerSuccess=data.trackerSuccess||[];const cp=curPeriod();(data.trackers||[]).forEach(t=>{if(!t.periodKey)t.periodKey=cp;if(!t.pending&&t.periodKey!==cp){if(isTrackerComplete(t)&&!data.trackerSuccess.some(s=>s.sourceId===t.id&&s.period===t.periodKey))data.trackerSuccess.push({id:uid(),sourceId:t.id,period:t.periodKey,title:t.title,target:t.target,days:[...(t.days||[])],month:periodLabel(t.periodKey),reward:t.reward,giftReceived:!!t.giftReceived,addedDate:key(),date:key()});t.pending=true}})}
    function commitDraftValue(){if(!editSession)return;const k=key();if(editSession.kind==='metric'){const el=document.getElementById('metricVal');if(el)editSession.values[k]=el.value}else if(editSession.kind==='builtin'){const el=document.getElementById('builtinVal');if(el)editSession.values[k]=el.value}}
    function resetToToday(){data.selectedYear=today.getFullYear();data.selectedMonth=today.getMonth();data.selectedDay=today.getDate();insightMonth=null;editSession=null;modal.classList.remove('open');renderAll()}

    let insightMonth=null, editSession=null, calendarEditOrigin=null, balanceSwapId=null, modalCloseTo=null, armedTracker=null, listSwapId=null, swapCtx=null;
    function snapshotSelectedDate(){return {y:data.selectedYear,m:data.selectedMonth,d:data.selectedDay}}
    function restoreSelectedDate(s){if(!s)return;data.selectedYear=s.y;data.selectedMonth=s.m;data.selectedDay=s.d;clampDay()}
    function beginCalendarEdit(){if(!calendarEditOrigin)calendarEditOrigin=snapshotSelectedDate()}
    function restoreCalendarEditOrigin(){const o=calendarEditOrigin;calendarEditOrigin=null;restoreSelectedDate(o)}
    function migrate(){data.balance=data.balance||structuredClone(seed.balance);data.dreams=data.dreams||[];data.lists=data.lists||[];data.trackerSuccess=(data.trackerSuccess||[]).map(s=>({...s,month:s.month&&s.month.includes('а ')?s.month.replace('января','январь').replace('февраля','февраль').replace('марта','март').replace('апреля','апрель').replace('мая','май').replace('июня','июнь').replace('июля','июль').replace('августа','август').replace('сентября','сентябрь').replace('октября','октябрь').replace('ноября','ноябрь').replace('декабря','декабрь'):s.month,addedDate:s.addedDate||s.date||key()}));data.bookArchive=(data.bookArchive||[]).map(b=>({...b,date:b.date||key()}));data.watchArchive=(data.watchArchive||[]).map(w=>({...w,date:w.date||key()}));data.trackers=(data.trackers||[]).map(t=>({...t,days:t.days||[],periodKey:t.periodKey||curPeriod(),pending:t.pending||false}));moveCompletedTrackers();data.metrics=(data.metrics||[]).map(m=>({...m,type:m.type==='да-нет'?'да/нет':m.type,unit:m.unit||unitFor(m.type),values:m.values||{}})); data.trackerSuccess=data.trackerSuccess||[]; data.bookArchive=data.bookArchive||[]; data.watchArchive=data.watchArchive||[]; data.watches=(data.watches||[]).map(w=>{if(w.type==='сериал')ensureSeries(w);return w}); data.watchArchive=(data.watchArchive||[]).map(w=>{if(w.type==='сериал')ensureSeries(w);return w}); data.goals=(data.goals||[]).map(g=>{g.sub=(g.sub||[]).map(s=>typeof s==='string'?{id:uid(),title:s,progress:0,status:'не начато',weight:''}:{...s,status:s.status||(s.done?'выполнено':((Number(s.progress)||0)>0?'в процессе':'не начато')),weight:s.weight??''}); goalProgress(g); return g}); moveFinishedMedia(); save()}
    function setScreen(name){if(name!=='balance')balanceSwapId=null;if(name!=='lists')listSwapId=null;swapCtx=null;document.querySelectorAll('.nav button').forEach(b=>b.classList.toggle('active',b.dataset.screen===name));document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));document.getElementById('screen-'+name).classList.add('active');document.body.classList.toggle('on-month',name==='month');const navBtn=document.querySelector('.nav button.active');if(navBtn)try{navBtn.scrollIntoView({behavior:'smooth',block:'nearest',inline:'center'})}catch(e){}}
    function openLibraryTab(sub){setScreen('library');document.querySelectorAll('#screen-library .tab').forEach(t=>t.classList.toggle('active',t.dataset.sub===sub));document.querySelectorAll('#screen-library .subscreen').forEach(s=>s.classList.remove('active'));const el=document.getElementById('sub-'+sub);if(el)el.classList.add('active')}
    function fitMonthSelect(){const el=window.monthSelect;if(!el||!el.options.length)return;const c=fitMonthSelect._c||(fitMonthSelect._c=document.createElement('canvas').getContext('2d'));const cs=getComputedStyle(el);c.font=`${cs.fontWeight} ${cs.fontSize} ${cs.fontFamily}`;const t=el.options[el.selectedIndex]?.textContent||'';const w=Math.ceil(c.measureText(t).width)+2;el.style.width=el.style.maxWidth=w+'px'}
    function renderSelectors(){monthSelect.innerHTML=months.map((m,i)=>`<option value="${i}">${m}</option>`).join('');monthSelect.value=data.selectedMonth;const y=today.getFullYear();yearSelect.innerHTML=[2025,2026,2027].map(v=>`<option>${v}</option>`).join('');if(![2025,2026,2027].includes(Number(data.selectedYear)))data.selectedYear=2026;yearSelect.value=data.selectedYear;fitMonthSelect()}
    function renderCalendar(){clampDay();renderSelectors();const first=new Date(data.selectedYear,data.selectedMonth,1),days=daysInMonth(),shift=(first.getDay()+6)%7,cells=[];for(let i=0;i<shift;i++)cells.push('<button class="day blank"></button>');for(let d=1;d<=days;d++){const k=key(data.selectedYear,data.selectedMonth,d),dd=data.days[k],cls=['day'];if(d===data.selectedDay)cls.push('selected');if(d===today.getDate()&&data.selectedMonth===today.getMonth()&&data.selectedYear===today.getFullYear())cls.push('today');cells.push(`<button class="${cls.join(' ')}" style="background:${gradientFor(dd?.emotions)}" data-day="${d}">${d}</button>`)}calendarGrid.innerHTML=cells.join('');if(window.calNavLabel){const mn=ruMonths[data.selectedMonth];calNavLabel.textContent=`${mn.charAt(0).toUpperCase()+mn.slice(1)} ${data.selectedYear}`}selectedDayTitle.textContent=dateLabel(data.selectedDay,data.selectedMonth,data.selectedYear,true);renderMini();renderMonthGoals();renderCurrentMedia()}
    
    function renderMini(){const d=dayData(),p=pulseData(),items=[['Оценки дня',isRatingsDone(d),'openRatings'],['Дневник',isJournalDone(d),'openJournal'],['Шаги',Number(p.steps)>1000,'openBuiltinMetric','steps'],['Чтение',Number(p.reading)>15,'openBuiltinMetric','reading']];miniTrackers.innerHTML=items.map(([t,ok,act,kind])=>`<div class="mini clickable" data-action="${act}" ${kind?`data-kind="${kind}"`:''}><span>${t}</span><i class="state ${ok?'done':''}"></i></div>`).join('');pulseDate.textContent=dateLabel();if(window.stepsInput){stepsInput.value=p.steps||'';readingInput.value=p.reading||''}if(window.stepsTotal)stepsTotal.textContent=builtinMonthTotalLabel('steps');if(window.readingTotal)readingTotal.textContent=builtinMonthTotalLabel('reading'); if(window.trackersDate)trackersDate.textContent=dateLabel(); if(window.goalsDate)goalsDate.textContent=dateLabel()}
    
    function renderMonthGoals(){monthGoals.innerHTML=data.goals.map(g=>{const gp=goalProgress(g);return`<div class="goal-row clickable" data-action="openGoal" data-id="${g.id}"><div style="flex:1"><b>${g.title}</b><div class="progress"><i style="width:${gp}%"></i></div></div><strong>${gp}%</strong></div>`}).join('')||'<div class="empty">Целей пока нет</div>'}
    
    function mediaCard(obj,empty){if(!obj)return`<div class="empty">${empty}</div>`;const isWatch=!!obj.type;const meta=obj.author||obj.director||(isWatch?'режиссёр не указан':'не указано');let pct;if(isWatch){if(obj.type==='сериал'){const t=seriesTotals(obj);pct=Math.min(100,(t.watched/(t.episodes||1))*100)}else{pct=obj.status==='закончен'?100:50}}else{pct=Math.min(100,(obj.done||0)/(obj.total||1)*100)}return`<div class="swipe"><div class="swipe-content clickable" data-action="${isWatch?'editWatch':'editBook'}" data-id="${obj.id}"><b>${obj.title}</b><div class="tiny">${meta}</div><div class="progress"><i style="width:${pct}%"></i></div></div></div>`}
    function renderCurrentMedia(){const book=data.books.find(b=>b.id===data.currentBookId&&b.status!=='прочитано');const watch=data.watches.find(w=>w.id===data.currentWatchId&&w.status!=='закончен');currentBook.innerHTML=mediaCard(book,'Нет активной книги');currentWatch.innerHTML=mediaCard(watch,'Нет активного просмотра')}
    function swipeCard(html,delAction,id,openAction){return`<div class="swipe"><div class="swipe-content ${openAction?'clickable':''}" ${openAction?`data-action="${openAction}" data-id="${id}"`:''}>${html}</div></div>`}
    function swapArr(kind,goal){return kind==='watch'?data.watches:kind==='book'?data.books:kind==='goal'?data.goals:kind==='metric'?data.metrics:kind==='tracker'?data.trackers:kind==='sub'?((data.goals.find(g=>g.id===goal)||{}).sub):null}
    function isPicked(kind,id,goal){return !!(swapCtx&&swapCtx.kind===kind&&swapCtx.id===id&&(swapCtx.goal||'')===(goal||''))}
    function moveBtn(kind,id,goal){return `<button type="button" class="list-move${isPicked(kind,id,goal)?' picked':''}" data-action="pickSwap" data-kind="${kind}" data-id="${id}"${goal?` data-goal="${goal}"`:''} aria-label="Поменять местами"><span class="move-ic">⇅</span></button>`}
    function swapHint(kind,goal){const arr=swapArr(kind,goal)||[];if(arr.length<2)return'';const active=swapCtx&&swapCtx.kind===kind&&(swapCtx.goal||'')===(goal||'');return active?`<div class="balance-hint">Выбрано — коснитесь ⇅ другого, чтобы поменять местами, или того же — отменить</div>`:''}
    function renderPulse(){renderMini();customMetrics.innerHTML=swapHint('metric')+data.metrics.map(m=>swipeCard(`<div class="list-head-left">${moveBtn('metric',m.id)}<b>${m.name}</b></div><div class="tiny">${metricTypeLabel(m)}</div><div class="field">${m.type==='да/нет'?`<select data-metric="${m.id}"><option value=""></option><option ${m.values?.[key()]==='да'?'selected':''}>да</option><option ${m.values?.[key()]==='нет'?'selected':''}>нет</option></select>`:`<input data-metric="${m.id}" placeholder="Значение${m.unit?' · '+m.unit:''}" value="${m.values?.[key()]||''}">`}</div>${m.type!=='текст'?`<div class="tiny metric-total">${metricMonthTotalLabel(m.type,m.unit,m.values)}</div>`:''}`,'deleteMetric',m.id,'openMetric')).join('')||'<div class="empty">Свои метрики еще не добавлены</div>'}
    function checkTrackerSuccess(t){moveCompletedTrackers()}
    function renderTrackers(){moveCompletedTrackers();trackerList.innerHTML=swapHint('tracker')+(data.trackers||[]).map(t=>{const n=(t.days||[]).length,pct=Math.round(Math.min(100,n/(t.target||1)*100)),done=isTrackerComplete(t);if(t.pending)return `<div class="swipe"><div class="swipe-content tracker-pending"><div class="section-title goal-head"><h3 class="goal-title">${t.title}</h3><strong>${pct}%</strong></div><div class="tiny goal-dates">${periodLabel(t.periodKey)}: ${n}/${t.target}${done?' · выполнено 🎉':''}</div><div class="progress"><i style="width:${pct}%"></i></div><p class="hint">Новый месяц — повтори привычку или удали</p><div class="modal-actions tracker-actions">${armedTracker===t.id?`<span class="del-q">Точно удалить?</span><button type="button" class="btn-yesdel" data-action="confirmDeleteTracker" data-id="${t.id}">Да, удаляю</button>`:`<button type="button" class="btn-del" data-action="armDeleteTracker" data-id="${t.id}">Удалить</button>`}<button class="btn" data-action="repeatTracker" data-id="${t.id}">Повторить</button></div></div></div>`;return swipeCard(`<div class="section-title goal-head"><div class="list-head-left">${moveBtn('tracker',t.id)}<h3 class="goal-title">${t.title}</h3></div><strong>${pct}%</strong></div><div class="tiny goal-dates">Цель: ${t.target} из ${daysInMonth()} дней · прогресс ${n}/${t.target}</div><div class="progress"><i style="width:${pct}%"></i></div><div class="hint reward-line">Подарок: ${t.reward||'не задан'}</div>`,'deleteTracker',t.id,'openTracker')}).join('')||'<div class="empty">Трекеров пока нет</div>';successList.innerHTML=`<div class="flat-card folder-card clickable" data-action="openSuccessArchive"><div class="folder-mark">A</div><div><b>Мои успехи</b><div class="tiny">${(data.trackerSuccess||[]).length} ${ruCount((data.trackerSuccess||[]).length,['достижение','достижения','достижений'])} внутри</div></div></div>`}
    function balanceArc(cx,cy,r1,r2,a0,a1){const rad=a=>(a-90)*Math.PI/180,p=(r,a)=>`${cx+r*Math.cos(rad(a))},${cy+r*Math.sin(rad(a))}`;const large=a1-a0>180?1:0;return `M${p(r2,a0)} A${r2},${r2} 0 ${large} 1 ${p(r2,a1)} L${p(r1,a1)} A${r1},${r1} 0 ${large} 0 ${p(r1,a0)} Z`}
    function balanceItems(){data.balance=data.balance||structuredClone(seed.balance);return data.balance.slice(0,12)}
    function balanceLabelLines(name){name=String(name||'').trim().replace(/\//g,'/ ');const words=name.split(/\s+/).map(w=>w.length>9?w.slice(0,8)+'…':w);const lines=[];let cur='';words.forEach(w=>{if(!cur)cur=w;else if((cur+' '+w).length<=9)cur+=' '+w;else{lines.push(cur);cur=w}});if(cur)lines.push(cur);if(lines.length>2){lines.length=2;if(lines[1].length>8)lines[1]=lines[1].slice(0,8)+'…'}return lines.map(l=>l.replace(/\/ /g,'/'))}
    function renderBalanceWheel(){if(!window.balanceWheel)return;const items=balanceItems(),n=items.length||1,cx=180,cy=180,r1=43,r2=126;let svg=`<svg class="balance-svg" viewBox="-31 18 424 316" role="img" aria-label="Колесо баланса"><defs><linearGradient id="balGrad" x1="0" y1="0" x2="1" y2="1"><stop offset="0" stop-color="#F27DA6"/><stop offset="1" stop-color="#D6336C"/></linearGradient></defs>`;items.forEach((it,i)=>{const a0=i*360/n,a1=(i+1)*360/n,score=Math.max(1,Math.min(10,Number(it.score)||1)),vr=r1+(r2-r1)*score/10,mid=(a0+a1)/2;svg+=`<g data-action="focusSector" data-id="${it.id}" style="cursor:pointer"><path d="${balanceArc(cx,cy,r1,r2,a0,a1)}" fill="#F9DCE5" stroke="#FFFEFA" stroke-width="1.5"/><path d="${balanceArc(cx,cy,r1,vr,a0,a1)}" fill="url(#balGrad)" stroke="#FFFEFA" stroke-width="1"/>`;const rad=(mid-90)*Math.PI/180,cos=Math.cos(rad),sin=Math.sin(rad),lines=balanceLabelLines(it.name),vert=Math.abs(sin),lr=r2+13+vert*(14+(lines.length-1)*5),lx=cx+lr*cos,ly=cy+lr*sin,anchor=cos>.35?'start':cos<-.35?'end':'middle',y0=ly+3.5-(lines.length-1)*5.5,nr=r1+(r2-r1)*0.38,nx=cx+nr*cos,ny=cy+nr*sin;svg+=`<text class="balance-num" x="${nx}" y="${ny+4.5}" text-anchor="middle">${score}</text><text class="balance-label" text-anchor="${anchor}">${lines.map((l,li)=>`<tspan x="${lx}" y="${y0+li*11}">${l}</tspan>`).join('')}</text></g>`});svg+=`<circle cx="${cx}" cy="${cy}" r="38" fill="#FFFEFA" stroke="#1E1B16" stroke-width="1.5"/><text x="${cx}" y="${cy+5}" text-anchor="middle" style="font-size:var(--fs-body);font-weight:800;fill:#1E1B16">Balance</text></svg>`;balanceWheel.innerHTML=`<div class="balance-wrap">${svg}</div>`}
    function balanceTodayKey(){return `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,'0')}-${String(today.getDate()).padStart(2,'0')}`}
    function renderBalanceDate(){data.balanceDate=data.balanceDate||balanceTodayKey();const el=document.getElementById('balanceDateEl');if(!el)return;const [y,m,d]=data.balanceDate.split('-').map(Number);el.textContent=`${d} ${ruMonthsGen[m-1]} ${y}`}
    function renderBalance(){if(!window.balanceWheel||!window.balanceList)return;renderBalanceDate();const items=balanceItems();if(balanceSwapId&&!items.some(x=>x.id===balanceSwapId))balanceSwapId=null;renderBalanceWheel();const picked=items.find(x=>x.id===balanceSwapId);const hint=picked?`<div class="balance-hint">Выбрана «${picked.name}» — коснитесь другой сферы, чтобы поменять местами, или её же — чтобы отменить</div>`:'';balanceList.innerHTML=hint+items.map(it=>{const score=Math.max(1,Math.min(10,Number(it.score)||1)),sel=it.id===balanceSwapId;return `<div class="flat-card balance-sector${sel?' picked':''}" data-sector="${it.id}"><div class="sector-top"><button class="balance-move" data-action="pickBalance" data-id="${it.id}"><span class="move-ic">⇅</span><b>${it.name}</b></button><button class="btn ghost" data-action="editBalanceSector" data-id="${it.id}">править</button></div>${it.desc?`<div class="balance-desc tiny">${it.desc}</div>`:''}<div class="balance-slider"><input type="range" min="1" max="10" value="${score}" data-balance-score="${it.id}"><strong data-balance-out="${it.id}">${score}</strong></div></div>`}).join('')}
    document.addEventListener('input',e=>{if(e.target.matches('[data-balance-score]')){const b=(data.balance||[]).find(x=>x.id===e.target.dataset.balanceScore);if(!b)return;b.score=Math.max(1,Math.min(10,Number(e.target.value)||1));const out=document.querySelector(`[data-balance-out="${b.id}"]`);if(out)out.textContent=b.score;save();renderBalanceWheel()}});
    function openBalanceSector(id){const b=(data.balance||[]).find(x=>x.id===id);if(!b)return;openSimple('Сфера баланса',`<div class="field"><label>Название</label><input id="balName" value="${b.name||''}"></div><div class="field"><label>Описание</label><input id="balDesc" value="${(b.desc||'').replace(/"/g,'&quot;')}" placeholder="например: тело, сон, энергия"></div><div class="slider-line"><b>Оценка</b><input id="balScore" type="range" min="1" max="10" value="${b.score||5}"><strong id="balScoreOut">${b.score||5}</strong></div>`,()=>{b.name=balName.value||b.name;b.desc=balDesc.value;b.score=Math.max(1,Math.min(10,Number(balScore.value)||5))},'Сохранить',()=>{data.balance=(data.balance||[]).filter(x=>x.id!==b.id);save();modal.classList.remove('open');renderAll()});const bs=document.getElementById('balScore');if(bs)bs.oninput=()=>{const o=document.getElementById('balScoreOut');if(o)o.textContent=bs.value}}
        function renderGoals(){goalsList.innerHTML=swapHint('goal')+data.goals.map(g=>{const gp=goalProgress(g);return swipeCard(`<div class="section-title goal-head"><div class="list-head-left">${moveBtn('goal',g.id)}<h3 class="goal-title">${g.title}</h3></div><strong>${gp}%</strong></div><div class="tiny goal-dates">${formatDate(g.from)} — ${formatDate(g.to)} · ${g.status}</div><p class="goal-desc">${previewText(g.desc||'',100)}</p><div class="progress"><i style="width:${gp}%"></i></div><div class="goal-subs">${(g.sub||[]).slice(0,10).map(s=>`<button class="pill" data-action="editSubgoal" data-goal="${g.id}" data-id="${s.id}">${s.title} · ${subProgress(s)}%</button>`).join('')||'<span class="hint">Подцелей нет</span>'}</div>`,'deleteGoal',g.id,'openGoal')}).join('')||'<div class="empty">Целей пока нет</div>'}
    function starText(r){const full=Math.floor(r),half=r%1>=.5;return'★'.repeat(full)+(half?'½':'')+'☆'.repeat(Math.max(0,5-full-(half?1:0)))}
    function moveFinishedMedia(){[...(data.books||[])].forEach(b=>{if(b.status==='прочитано'){data.bookArchive=data.bookArchive||[]; if(!data.bookArchive.some(x=>x.sourceId===b.id||x.id===b.id))data.bookArchive.push({...b,id:uid(),sourceId:b.id,date:key(),rating:b.rating||'',review:b.review||'',quote:b.quote||''}); if(data.currentBookId===b.id)data.currentBookId=''; data.books=data.books.filter(x=>x.id!==b.id)}});[...(data.watches||[])].forEach(w=>{if(w.status==='закончен'){data.watchArchive=data.watchArchive||[]; if(w.type==='сериал')ensureSeries(w); if(!data.watchArchive.some(x=>x.sourceId===w.id||x.id===w.id))data.watchArchive.push({...w,id:uid(),sourceId:w.id,date:key(),rating:w.rating||5,review:w.review||''}); if(data.currentWatchId===w.id)data.currentWatchId=''; data.watches=data.watches.filter(x=>x.id!==w.id)}})}
    
    function currentSeasonLabel(w){if(w.type!=='сериал')return'';ensureSeries(w);const idx=(w.seasonsData||[]).findIndex(s=>Number(s.watched||0)<Number(s.episodes||0));const i=idx>=0?idx:(w.seasonsData||[]).length-1,s=(w.seasonsData||[])[i]||{episodes:0,watched:0};return `${i+1} сезон · ${Number(s.watched||0)}/${Number(s.episodes||0)} серий`}
    function archiveSeriesLabel(w){ensureSeries(w);const total=seriesTotals(w).episodes;return `${w.seasons||((w.seasonsData||[]).length)} ${ruCount(w.seasons||((w.seasonsData||[]).length),['сезон','сезона','сезонов'])} · ${total} ${ruCount(total,['серия','серии','серий'])}`}
    function renderLibrary(){moveFinishedMedia();activeBooks.innerHTML=swapHint('book')+data.books.map(b=>swipeCard(`<div class="section-title"><div class="list-head-left">${moveBtn('book',b.id)}<h3 class="media-title">${b.title}</h3></div><select data-book-status="${b.id}"><option ${b.status==='читаю'?'selected':''}>читаю</option><option ${b.status==='пауза'?'selected':''}>пауза</option><option ${b.status==='прочитано'?'selected':''}>прочитано</option></select></div><div class="tiny">${b.author} · ${b.done}/${b.total} ${b.mode==='pages'?'стр.':'мин.'}</div><div class="progress"><i style="width:${Math.min(100,b.done/(b.total||1)*100)}%"></i></div>`,'deleteBook',b.id,'editBook')).join('')||'<div class="empty">Активных книг нет</div>';bookArchive.innerHTML=`<div class="flat-card folder-card clickable" data-action="openBookArchive"><div class="folder-mark">B</div><div><b>${bookArchiveTitle()}</b><div class="tiny">открыть список</div></div></div>`;activeWatch.innerHTML=swapHint('watch')+data.watches.map(w=>{const t=w.type==='сериал'?seriesTotals(w):null,label=w.type==='сериал'?`${w.director?w.director+' · ':''}${currentSeasonLabel(w)}`:(w.director||'');return swipeCard(`<div class="section-title"><div class="list-head-left">${moveBtn('watch',w.id)}<h3 class="media-title">${w.title}</h3></div><select data-watch-status="${w.id}"><option ${w.status==='смотрю'?'selected':''}>смотрю</option><option ${w.status==='пауза'?'selected':''}>пауза</option><option ${w.status==='закончен'?'selected':''}>закончен</option></select></div><div class="tiny">${w.type}${label?' · '+label:''}</div><div class="progress"><i style="width:${t?Math.min(100,t.watched/(t.episodes||1)*100):(w.status==='закончен'?100:50)}%"></i></div>`,'deleteWatch',w.id,'editWatch')}).join('')||'<div class="empty">Активного просмотра нет</div>';watchArchive.innerHTML=`<div class="flat-card folder-card clickable" data-action="openWatchArchive"><div class="folder-mark">F</div><div><b>${watchArchiveTitle()}</b><div class="tiny">открыть список</div></div></div>`}
        function renderInsights(){const rows=Object.entries(data.days).filter(([k,d])=>d.journal?.insight?.trim()).sort().reverse();if(window.insightCloseBtn)insightCloseBtn.classList.toggle('hidden',!insightMonth);if(!insightMonth){const groups={};rows.forEach(([k,d])=>{const [y,m]=k.split('-');const id=`${y}-${m}`;groups[id]=(groups[id]||0)+1});const cards=Object.entries(groups).sort().reverse().map(([id,count])=>{const [y,m]=id.split('-').map(Number);return `<div class="flat-card folder-card clickable" data-action="openInsightMonth" data-id="${id}"><div class="folder-mark">M</div><div><b>${formatMonthNom(y,m-1,true)}</b><div class="tiny">${formatInsightCount(count)}</div></div></div>`}).join('');insightsList.innerHTML=cards||'<div class="empty">Инсайтов пока нет</div>';return}const monthRows=rows.filter(([k])=>k.startsWith(insightMonth)).reverse();insightsList.innerHTML=(monthRows.map(([k,d])=>`<div class="flat-card"><h3>${formatDate(k)}</h3><p>${d.journal.insight}</p><button class="btn secondary" data-open-date="${k}">Открыть день</button></div>`).join('')||'<div class="empty">В этом месяце записей нет</div>')}
        function listIsDone(l){const n=(l.items||[]).length;return n>0&&l.items.every(i=>i.done)}
        function syncListCompletion(l){if(listIsDone(l)){if(!l.completedAt)l.completedAt=key()}else{l.completedAt=null}}
        function renderLists(){if(!window.listsList)return;const lists=data.lists||[];if(listSwapId&&!lists.some(x=>x.id===listSwapId))listSwapId=null;const picked=lists.find(x=>x.id===listSwapId);const hint=lists.length>1&&picked?`<div class="balance-hint">Выбран «${picked.title}» — коснитесь ⇅ другого списка, чтобы поменять местами, или его же — чтобы отменить</div>`:'';const ordered=[...lists].sort((a,b)=>(listIsDone(a)?1:0)-(listIsDone(b)?1:0));listsList.innerHTML=hint+ordered.map(l=>{const n=(l.items||[]).length,done=(l.items||[]).filter(i=>i.done).length,pct=n?Math.round(done/n*100):0,sel=l.id===listSwapId,fin=listIsDone(l);return `<div class="swipe"><div class="swipe-content clickable list-card${sel?' picked':''}${fin?' done':''}" data-action="openList" data-id="${l.id}"><div class="section-title goal-head"><div class="list-head-left"><button type="button" class="list-move" data-action="pickList" data-id="${l.id}" aria-label="Поменять местами"><span class="move-ic">⇅</span></button><h3 class="goal-title">${l.title}</h3></div><strong>${pct}%</strong></div><div class="tiny goal-dates">${formatDate(l.createdAt)} · ${done}/${n}</div><div class="progress"><i style="width:${pct}%"></i></div>${fin?`<div class="tiny list-done-badge">✓ выполнено ${formatDate(l.completedAt)}</div>`:''}</div></div>`}).join('')||'<div class="empty">Списков пока нет. Создай первый!</div>'}
        function openList(id){const l=(data.lists||[]).find(x=>x.id===id);if(!l)return;modalCloseTo=null;modalTitle.textContent=l.title;const esc=s=>String(s||'').replace(/"/g,'&quot;');const rows=(l.items||[]).map(it=>`<div class="list-row"><button type="button" class="list-check ${it.done?'done':''}" data-action="toggleListItem" data-list="${l.id}" data-item="${it.id}" aria-label="Выполнено"></button><input class="list-text-input ${it.done?'done':''}" data-item-text="${it.id}" value="${esc(it.text)}"><button type="button" class="list-del" data-action="deleteListItem" data-list="${l.id}" data-item="${it.id}" aria-label="Удалить пункт">✕</button></div>`).join('')||'<div class="empty">Пунктов пока нет</div>';modalBody.innerHTML=`<div class="field"><label>Название списка</label><input id="listTitle" value="${esc(l.title)}"></div><div id="listRows">${rows}</div><div class="list-add"><input id="newListItem" placeholder="Новый пункт"><button class="btn secondary" type="button" data-action="addListItem" data-list="${l.id}">Добавить</button></div><div class="modal-actions"><button type="button" class="btn-del" id="listDelete">Удалить список</button><button class="btn" id="listSave">Сохранить</button></div>`;modalBody.dataset.listId=l.id;modal.classList.add('open');const ni=document.getElementById('newListItem');if(ni)ni.onkeydown=ev=>{if(ev.key==='Enter'){ev.preventDefault();listAddItem(l.id)}};const sv=document.getElementById('listSave');if(sv)sv.onclick=()=>{syncListInputs(l);save();modal.classList.remove('open');renderAll()};wireDelete(document.getElementById('listDelete'),()=>{data.lists=data.lists.filter(x=>x.id!==l.id);save();modal.classList.remove('open');renderAll()})}
        function syncListInputs(l){if(!l)return;const t=document.getElementById('listTitle');if(t)l.title=t.value.trim()||l.title;document.querySelectorAll('#listRows [data-item-text]').forEach(inp=>{const it=(l.items||[]).find(x=>x.id===inp.dataset.itemText);if(it)it.text=inp.value})}
        function listAddItem(id){const l=(data.lists||[]).find(x=>x.id===id);if(!l)return;syncListInputs(l);const inp=document.getElementById('newListItem');const t=(inp?.value||'').trim();if(!t)return;l.items=l.items||[];l.items.push({id:uid(),text:t,done:false});syncListCompletion(l);save();openList(id)}
        function dreamPreview(t){t=t||'';return t.length>100?t.slice(0,100)+'…':t}
        function renderDreams(){const active=(data.dreams||[]).filter(d=>!d.done).sort((a,b)=>dateStamp(b.date).localeCompare(dateStamp(a.date)));const dl=document.getElementById('dreamList');if(dl)dl.innerHTML=active.map(d=>`<div class="flat-card clickable dream-card" data-action="openDream" data-id="${d.id}"><p class="dream-text">${dreamPreview(d.text)}</p><div class="tiny">${formatDate(d.date)}</div></div>`).join('')||'<div class="empty">Пока нет желаний. Загадай первое!</div>';const done=(data.dreams||[]).filter(d=>d.done).length;const df=document.getElementById('dreamArchiveFolder');if(df)df.innerHTML=`<div class="flat-card folder-card clickable" data-action="openDreamArchive"><div class="folder-mark">★</div><div><b>${done} исполнено</b><div class="tiny">открыть список</div></div></div>`}
        function openDream(id){const d=(data.dreams||[]).find(x=>x.id===id);if(!d)return;const field=`<div class="field"><label>Моя мечта</label><textarea id="dreamText" class="dream-edit">${d.text||''}</textarea></div>`;if(d.done){openSimple('Сбывшееся',`${field}<div class="pill dream-done-pill">Исполнено · ${formatDate(d.doneDate||d.date)}</div>`,()=>{const ta=document.getElementById('dreamText');if(ta)d.text=ta.value;save()},'',()=>{data.dreams=data.dreams.filter(x=>x.id!==d.id);save();openDreamArchive()});modalCloseTo=openDreamArchive}else{openSimple('Моё желание',`${field}<div class="tiny">Загадано ${formatDate(d.date)}</div>`,()=>{const ta=document.getElementById('dreamText');if(ta)d.text=ta.value;d.done=true;d.doneDate=key();save()},'Спасибо, исполнено',()=>{data.dreams=data.dreams.filter(x=>x.id!==d.id);save();modal.classList.remove('open');renderAll()})}modalBody.dataset.dreamId=d.id}
        function openDreamArchive(){const rows=(data.dreams||[]).filter(d=>d.done).sort((a,b)=>dateStamp(b.doneDate||b.date).localeCompare(dateStamp(a.doneDate||a.date)));openSimple('Сбывшееся',rows.map(d=>`<div class="flat-card clickable dream-card" data-action="openDream" data-id="${d.id}"><p class="dream-text">${dreamPreview(d.text)}</p><div class="tiny">Исполнено · ${formatDate(d.doneDate||d.date)}</div></div>`).join('')||'<div class="empty">Пока ничего не сбылось</div>',()=>{},'')}
        function renderAll(){renderCalendar();renderPulse();renderTrackers();renderBalance();renderGoals();renderLibrary();renderLists();renderDreams();renderInsights();save();initSwipe()}
    function openDay(){modalCloseTo=null;const d=dayData();modalTitle.textContent=dateLabel(data.selectedDay,data.selectedMonth,data.selectedYear,true);modalBody.innerHTML=`<h3>Оценки дня</h3><div class="emotion-grid">${emotions.map(e=>`<button class="emotion ${d.emotions.includes(e[0])?'active':''}" data-emotion="${e[0]}"><i class="swatch" style="background:${e[2]}"></i>${e[1]}</button>`).join('')}</div>${[['energy','Энергия'],['anxiety','Тревожность'],['wellbeing','Самочувствие'],['sociality','Социальность'],['satisfaction','Удовлетворенность днем']].map(([id,label])=>`<div class="slider-line"><b>${label}</b><input type="range" min="1" max="5" value="${d.ratings[id]||3}" data-rating="${id}"><strong id="out-${id}">${d.ratings[id]||3}</strong></div>`).join('')}<h3>Дневник</h3><div class="field"><label>Благодарность этому дню</label><textarea data-journal="thanksDay">${d.journal.thanksDay}</textarea></div><div class="field"><label>Благодарность себе</label><textarea data-journal="thanksSelf">${d.journal.thanksSelf}</textarea></div><div class="field"><label>Главное за день</label><textarea data-journal="main">${d.journal.main}</textarea></div><div class="field"><label>Мысль / инсайт</label><textarea data-journal="insight">${d.journal.insight}</textarea></div><button class="btn" id="saveDayBtn">Сохранить день</button>`;modal.classList.add('open')}
    function openSimple(title,html,onSave,saveText='Сохранить',onDelete=null){modalCloseTo=null;modalTitle.textContent=title;const actions=(onDelete||saveText)?`<div class="modal-actions">${onDelete?'<button type="button" class="btn-del" id="simpleDelete">Удалить</button>':''}${saveText?`<button class="btn" id="simpleSave">${saveText}</button>`:''}</div>`:'';modalBody.innerHTML=html+actions;modal.classList.add('open');initSwipe();const btn=document.getElementById('simpleSave');if(btn)btn.onclick=()=>{onSave();modal.classList.remove('open');renderAll()};wireDelete(document.getElementById('simpleDelete'),onDelete)}
    function wireDelete(del,onDelete){if(!del||!onDelete)return;del.onclick=()=>{const grp=document.createElement('span');grp.className='del-confirm';grp.innerHTML='<span class="del-q">Точно удалить?</span><button type="button" class="btn-yesdel">Да, удаляю</button>';del.replaceWith(grp);const tmr=setTimeout(()=>{if(grp.isConnected)grp.replaceWith(del)},4000);grp.querySelector('.btn-yesdel').onclick=()=>{clearTimeout(tmr);onDelete()}}}

    function typeOptions(sel='число'){return['число','минуты','литры','километры','да/нет','другое'].map(x=>`<option ${sel===x?'selected':''}>${x}</option>`).join('')}
    function monthMiniCalendar(valueFn,cls='metric-day'){return `<div class="calendar-week"><span>Mon</span><span>Tue</span><span>Wed</span><span>Thu</span><span>Fri</span><span>Sat</span><span>Sun</span></div><div class="${cls==='tracker-day'?'tracker-calendar':'metric-calendar'}">${Array.from({length:(new Date(data.selectedYear,data.selectedMonth,1).getDay()+6)%7},()=>'<div></div>').join('')}${Array.from({length:daysInMonth()},(_,i)=>{const d=i+1,v=valueFn(d),sel=d===data.selectedDay?' selected':'';return `<div class="${cls} ${v?'done':''}${sel}" data-cal-day="${d}"><b>${d}</b>${v?`<span>${v}</span>`:''}</div>`}).join('')}</div>`}
    
    function openBuiltinMetric(kind){beginCalendarEdit();const isSteps=kind==='steps';if(!editSession||editSession.kind!=='builtin'||editSession.metricKind!==kind)editSession={kind:'builtin',metricKind:kind,values:{}};for(let d=1;d<=daysInMonth();d++){const k=key(data.selectedYear,data.selectedMonth,d);if(editSession.values[k]===undefined)editSession.values[k]=pulseData(k)[isSteps?'steps':'reading']||''}openSimple(isSteps?'Шаги':'Чтение за день',`<div class="pill metric-type">${isSteps?'число':'минуты'}</div><div class="tiny metric-total modal-total">${builtinMonthTotalLabel(kind,editSession.values)}</div><div id="draftCalendar">${monthMiniCalendar(d=>editSession.values[key(data.selectedYear,data.selectedMonth,d)]||'')}</div><div class="field"><label>День ${dateLabel()}</label><input id="builtinVal" type="number" min="0" value="${editSession.values[key()]||''}"></div>`,()=>{Object.entries(editSession.values).forEach(([k,v])=>{const cur=pulseData(k);cur[isSteps?'steps':'reading']=v;cur.readingUnit='минуты'});editSession=null;restoreCalendarEditOrigin()});modalBody.dataset.calendarMode='builtin';modalBody.dataset.kind=kind}
    function openMetric(id){beginCalendarEdit();const m=data.metrics.find(x=>x.id===id);if(!m)return;if(!editSession||editSession.kind!=='metric'||editSession.id!==id)editSession={kind:'metric',id,values:{...(m.values||{})}};openSimple(m.name,`<div class="pill metric-type">${metricTypeLabel(m)}</div>${m.type!=='текст'?`<div class="tiny metric-total modal-total">${metricMonthTotalLabel(m.type,m.unit,editSession.values)}</div>`:''}<div id="draftCalendar">${monthMiniCalendar(d=>editSession.values[key(data.selectedYear,data.selectedMonth,d)]||'')}</div><div class="field"><label>День ${dateLabel()}</label>${m.type==='да/нет'?`<select id="metricVal"><option value=""></option><option ${editSession.values[key()]==='да'?'selected':''}>да</option><option ${editSession.values[key()]==='нет'?'selected':''}>нет</option></select>`:`<input id="metricVal" value="${editSession.values[key()]||''}" placeholder="Значение${m.unit?' · '+m.unit:''}">`}</div><div class="field"><label>Название</label><input id="mTitle" value="${m.name}"></div>${metricTypeEditor(m)}`,()=>{commitDraftValue();m.values={...editSession.values};m.name=mTitle.value||m.name;m.type=mType.value;m.unit=mType.value==='другое'?mUnit.value:unitFor(mType.value);editSession=null;restoreCalendarEditOrigin()},'Сохранить',()=>{data.metrics=data.metrics.filter(x=>x.id!==id);editSession=null;restoreCalendarEditOrigin();save();modal.classList.remove('open');renderAll()});modalBody.dataset.calendarMode='metric';modalBody.dataset.id=id}
    function openTracker(id){beginCalendarEdit();const t=data.trackers.find(x=>x.id===id);if(!t)return;if(!editSession||editSession.kind!=='tracker'||editSession.id!==id)editSession={kind:'tracker',id,days:[...(t.days||[])]};const dayOn=editSession.days.includes(data.selectedDay);openSimple(t.title,`<div id="draftCalendar">${monthMiniCalendar(d=>editSession.days.includes(d)?'✓':'','tracker-day')}</div><div class="field"><label>День ${dateLabel()}</label><select id="trackerYes"><option value="yes" ${dayOn?'selected':''}>да</option><option value="no" ${!dayOn?'selected':''}>нет</option></select></div><div class="field"><label>Название</label><input id="tTitle" value="${t.title}"></div><div class="field"><label>Цель дней в месяц</label><input id="tTarget" type="number" value="${t.target}"></div><div class="field"><label>Подарок</label><input id="tReward" value="${t.reward||''}"></div>`,()=>{t.title=tTitle.value||t.title;t.target=Number(tTarget.value)||t.target;t.reward=tReward.value||'';t.days=[...editSession.days];editSession=null;moveCompletedTrackers();restoreCalendarEditOrigin()},'Сохранить',()=>{data.trackers=data.trackers.filter(x=>x.id!==id);editSession=null;restoreCalendarEditOrigin();save();modal.classList.remove('open');renderAll()});modalBody.dataset.calendarMode='tracker';modalBody.dataset.id=id}
    
    function openSuccess(id){const s=(data.trackerSuccess||[]).find(x=>x.id===id||x.sourceId===id);if(!s)return;openSimple('Мои успехи',`<h3 class="success-detail-title">${s.title}</h3><p>${s.days.length}/${s.target} дней · ${s.month||''}</p><p>Подарок: ${s.reward||'не задан'}</p><div class="field"><label class="success-gift-label">Подарок получен</label><select id="gift"><option value="false">нет</option><option value="true" ${s.giftReceived?'selected':''}>да</option></select></div>`,()=>{},'Сохранить',()=>{data.trackerSuccess=(data.trackerSuccess||[]).filter(x=>x.id!==s.id);save();openSuccessArchive()});modalCloseTo=openSuccessArchive;const sb=document.getElementById('simpleSave');if(sb)sb.onclick=()=>{s.giftReceived=document.getElementById('gift').value==='true';save();openSuccessArchive()}}
    function openBookArchive(){openSimple('Библиотека',[...(data.bookArchive||[])].sort((a,b)=>dateStamp(b.date).localeCompare(dateStamp(a.date))).map(b=>swipeCard(`<h3 class="media-title">${b.title}</h3><div class="tiny">${b.author||''} · ${formatDate(b.date)} · ${volumeLabel(b)}</div><div class="stars">${b.rating?starText(b.rating):'Оценка не задана'}</div>${b.review?`<p class="review-preview">${previewText(b.review)}</p>`:''}`,'deleteArchiveBook',b.id,'editArchiveBook')).join('')||'<div class="empty">Пусто</div>',()=>{},'')}
    function openWatchArchive(){openSimple('Фильмотека',[...(data.watchArchive||[])].sort((a,b)=>dateStamp(b.date).localeCompare(dateStamp(a.date))).map(w=>{if(w.type==='сериал')ensureSeries(w);const dir=w.director?` · ${w.director}`:'';const tail=w.type==='сериал'?` · ${archiveSeriesLabel(w)}`:'';const ret=w.type==='сериал'?`<button class="btn secondary archive-action" data-action="returnWatch" data-id="${w.id}">Вернуть в Сейчас смотрю</button>`:'';return swipeCard(`<h3 class="media-title">${w.title}</h3><div class="tiny">${w.type}${dir} · ${formatDate(w.date)}${tail}</div><div class="stars">${w.rating?starText(w.rating):'Оценка не задана'}</div>${w.review?`<p class="review-preview">${previewText(w.review)}</p>`:''}${ret}`,'deleteArchiveWatch',w.id,'editArchiveWatch')}).join('')||'<div class="empty">Пусто</div>',()=>{},'')}
    function openSuccessArchive(){const rows=[...(data.trackerSuccess||[])].sort((a,b)=>dateStamp(b.addedDate||b.date).localeCompare(dateStamp(a.addedDate||a.date)));openSimple('Мои успехи',rows.map(s=>`<div class="flat-card clickable success-card" data-action="openSuccess" data-id="${s.id}"><h3>${s.title} ${s.days.length}/${s.target} дней</h3><div class="tiny">${s.month||''} · добавлено ${formatDate(s.addedDate||s.date)} · подарок: ${s.reward||'не задан'}</div><div class="pill success-gift">${s.giftReceived?'подарок получен':'подарок не отмечен'}</div></div>`).join('')||'<div class="empty">Пусто</div>',()=>{},'')}
    function openGoal(id){modalCloseTo=null;const g=data.goals.find(x=>x.id===id);if(!g)return;const gp=goalProgress(g),warn=goalWeightWarning(g);modalTitle.textContent=g.title;modalBody.innerHTML=`<div class="field"><label>Название</label><input id="gTitle" value="${g.title}"></div><div class="field"><label>Описание</label><textarea id="gDesc">${g.desc||''}</textarea></div><div class="two"><div class="field clickable" data-action="pickGoalDate"><label>Начало</label><input id="gFromDisp" readonly data-iso="${g.from||''}" value="${g.from?formatDate(g.from):'выбрать'}"></div><div class="field clickable" data-action="pickGoalDate"><label>Окончание</label><input id="gToDisp" readonly data-iso="${g.to||''}" value="${g.to?formatDate(g.to):'выбрать'}"></div></div><div class="pill">Прогресс считается автоматически: ${gp}%</div><h3 class="goal-subs-head">Подцели</h3><div id="subList">${swapHint('sub',g.id)}${(g.sub||[]).map((s,i)=>swipeCard(`<div class="list-head-left">${moveBtn('sub',s.id,g.id)}<b class="sub-name">${s.title}</b></div><div class="tiny">${subProgress(s)}% · вес ${s.weight===''?Math.round(effectiveWeights(g.sub||[])[i])+'% (поровну)':s.weight+'%'} · ${s.status}</div>`,'deleteSubgoal',s.id,'editSubgoal').replaceAll('data-id="'+s.id+'"','data-id="'+s.id+'" data-goal="'+g.id+'"')).join('')||'<div class="empty sub-empty">Подцелей пока нет</div>'}</div><button class="btn secondary goal-addsub" data-action="addSubgoal" data-id="${g.id}">Добавить подцель</button><div class="warning ${warn?'show':''}">Суммарный вес подцелей больше 100%. Уменьши один из весов</div><div class="modal-actions"><button type="button" class="btn-del" id="goalDelete">Удалить</button><button class="btn" id="saveGoalDetail">Сохранить цель</button></div>`;modal.classList.add('open');initSwipe();document.getElementById('saveGoalDetail').onclick=()=>{g.title=gTitle.value;g.desc=gDesc.value;g.from=gFromDisp.dataset.iso;g.to=gToDisp.dataset.iso;goalProgress(g);modal.classList.remove('open');renderAll()};wireDelete(document.getElementById('goalDelete'),()=>{data.goals=data.goals.filter(x=>x.id!==g.id);save();modal.classList.remove('open');renderAll()})}
    
    function openSubgoal(goalId,subId){const g=data.goals.find(x=>x.id===goalId),s=g?.sub.find(x=>x.id===subId);if(!s)return;openSimple('Подцель',`<div class="field"><label>Название</label><input id="sTitle" value="${s.title}"></div><div class="field"><label>Статус</label><select id="sStatus"><option ${s.status==='не начато'?'selected':''}>не начато</option><option ${s.status==='в процессе'?'selected':''}>в процессе</option><option ${s.status==='выполнено'?'selected':''}>выполнено</option></select></div><div class="field"><label>Прогресс, % — только если “в процессе”</label><input id="sProgress" type="number" min="0" max="100" value="${subProgress(s)}"></div><div class="field"><label>Вес подцели, %</label><input id="sWeight" type="number" min="0" max="100" value="${s.weight??''}"></div>`,()=>{},'Сохранить',()=>{g.sub=g.sub.filter(x=>x.id!==subId);normalizeGoalWeights(g);goalProgress(g);save();modal.classList.remove('open');setScreen('goals');renderAll()});modalCloseTo=null;const ssb=document.getElementById('simpleSave');if(ssb)ssb.onclick=()=>{s.title=sTitle.value;s.status=sStatus.value;s.done=s.status==='выполнено';s.progress=s.status==='выполнено'?100:(s.status==='не начато'?0:Number(sProgress.value)||0);s.weight=sWeight.value===''?'':Number(sWeight.value);normalizeGoalWeights(g);goalProgress(g);save();modal.classList.remove('open');setScreen('goals');renderAll()}}
    
    function editBook(id,archive=false){const arr=archive?data.bookArchive:data.books,b=arr.find(x=>x.id===id);if(!b)return;if(archive){openSimple('Книга в библиотеке',`<div class="field"><label>Название</label><input id="bTitle" value="${b.title}"></div><div class="field"><label>Автор</label><input id="bAuthor" value="${b.author||''}"></div><div class="field"><label>Объем</label><select id="bMode"><option value="pages" ${b.mode!=='minutes'?'selected':''}>страницы</option><option value="minutes" ${b.mode==='minutes'?'selected':''}>минуты</option></select><input id="bTotal" type="number" value="${b.total||0}"></div><div class="field"><label>Оценка</label><input id="bRating" type="number" min="1" max="5" step=".5" value="${b.rating||''}"></div><div class="field"><label>Отзыв</label><textarea id="bReview">${b.review||''}</textarea></div><div class="field"><label>Цитаты</label><textarea id="bQuote">${b.quote||b.quotes||''}</textarea></div>`,()=>{},'Сохранить',()=>{data.bookArchive=data.bookArchive.filter(x=>x.id!==b.id);save();openBookArchive()});modalCloseTo=openBookArchive;const sb=document.getElementById('simpleSave');if(sb)sb.onclick=()=>{b.title=bTitle.value;b.author=bAuthor.value;b.mode=bMode.value;b.total=Number(bTotal.value)||0;b.rating=bRating.value?Number(bRating.value):'';b.review=bReview.value;b.quote=bQuote.value;save();openBookArchive()};return}openSimple('Книга',`<div class="field"><label>Название</label><input id="bTitle" value="${b.title}"></div><div class="field"><label>Автор</label><input id="bAuthor" value="${b.author||''}"></div><div class="field"><label>Прогресс</label><input id="bDone" type="number" value="${b.done||0}"></div><div class="field"><label>Всего</label><input id="bTotal" type="number" value="${b.total||1}"></div>`,()=>{b.title=bTitle.value;b.author=bAuthor.value;b.done=Number(bDone.value)||0;b.total=Number(bTotal.value)||1},'Сохранить',()=>{data.books=data.books.filter(x=>x.id!==b.id);save();modal.classList.remove('open');renderAll()})}
    
    function editWatch(id,archive=false){const arr=archive?data.watchArchive:data.watches,w=arr.find(x=>x.id===id);if(!w)return;if(w.type==='сериал')ensureSeries(w);let seasonHtml='';if(w.type==='сериал'&&!archive)seasonHtml=`<h3 class="seasons-head">Сезоны</h3>${seriesSeasonFields((w.seasonsData||[]).length,w.seasonsData||[])}<button class="btn secondary season-add" type="button" data-action="addSeasonField">Добавить сезон</button>`;if(w.type==='сериал'&&archive)seasonHtml=`<div class="pill">${archiveSeriesLabel(w)}</div>`;const reviewHtml=archive||w.review?`<div class="field"><label>Отзыв</label><textarea id="wReview">${w.review||''}</textarea></div>`:'';const ratingHtml=archive?`<div class="field"><label>Оценка</label><input id="wRating" type="number" min="1" max="5" step=".5" value="${w.rating||''}"></div>`:'';openSimple(archive?'Просмотр в фильмотеке':'Просмотр',`<div class="field"><label>Название</label><input id="wTitle" value="${w.title||''}"></div><div class="field"><label>Режиссер</label><input id="wDirector" value="${w.director||''}"></div><div class="field"><label>Актеры</label><input id="wActors" value="${w.actors||''}"></div>${seasonHtml}${ratingHtml}${reviewHtml}`,()=>{},'Сохранить',()=>{if(archive){data.watchArchive=data.watchArchive.filter(x=>x.id!==w.id);save();openWatchArchive()}else{data.watches=data.watches.filter(x=>x.id!==w.id);save();modal.classList.remove('open');renderAll()}});if(archive)modalCloseTo=openWatchArchive;const wsb=document.getElementById('simpleSave');if(wsb)wsb.onclick=()=>{w.title=wTitle.value;w.director=wDirector.value;w.actors=wActors.value;if(document.getElementById('wReview'))w.review=wReview.value;if(document.getElementById('wRating'))w.rating=wRating.value?Number(wRating.value):'';if(w.type==='сериал'&&!archive){w.seasonsData=Array.from(document.querySelectorAll('[data-season-row]')).map(row=>({episodes:Number(row.querySelector('[data-season-episodes]')?.value)||0,watched:Number(row.querySelector('[data-season-watched]')?.value)||0,done:false}));ensureSeries(w)}save();if(archive){openWatchArchive()}else{modal.classList.remove('open');renderAll()}}}
    
function seriesSeasonFields(count,values=[]){count=Math.max(1,Number(count)||1);return Array.from({length:count},(_,i)=>{const s=values[i]||{};return `<div class="series-row" data-season-row><div class="field"><label>Серий в ${i+1} сезоне</label><input data-season-episodes="${i}" type="number" value="${s.episodes||0}"></div><div class="field"><label>Просмотрено в ${i+1} сезоне</label><input data-season-watched="${i}" type="number" value="${s.watched||0}"></div>${values.length?`<button class="btn ghost season-remove" type="button" data-action="deleteSeasonField">Удалить</button>`:''}</div>`}).join('')}
    function syncNewSeriesFields(){const box=document.getElementById('seriesSeasonList'), n=document.getElementById('fSeasons');if(box&&n)box.innerHTML=seriesSeasonFields(n.value)}

    function initSwipe(){document.querySelectorAll('[data-swipe]').forEach(el=>{let sx=0;el.ontouchstart=e=>sx=e.touches[0].clientX;el.ontouchend=e=>{const dx=e.changedTouches[0].clientX-sx;if(dx<-55)el.classList.add('open');if(dx>35)el.classList.remove('open')}})}
    function changeMonth(delta){data.selectedMonth+=delta;if(data.selectedMonth>11){data.selectedMonth=0;data.selectedYear++}if(data.selectedMonth<0){data.selectedMonth=11;data.selectedYear--}clampDay();renderAll();monthCalendarCard.classList.remove('slide-left','slide-right');void monthCalendarCard.offsetWidth;monthCalendarCard.classList.add(delta>0?'slide-left':'slide-right')}
